// Verify /api/wind-alert returns 400 for out-of-range coordinates.
// These are valid numbers (pass schema typing) but fail the range check in withValidatedCoords.
async function testWindAlertOutOfRange() {
  const res = await fetch('http://localhost:3001/api/wind-alert?lat=100&lon=50');
  assertEquals(res.status, 400, 'Out-of-range coords should return 400');
  const body = await res.json();
  assertEquals(body.error, true, 'Should report an error');
  assertEquals(body.message, 'Invalid coordinates: lat must be -90..90, lon must be -180..180', 'Should return the range error message');
}
